    "css": "/* From Uiverse.io by Juanes200122  - Tags: 3d, loader, svg, creative, box, computer, server */\n.container_SevMini {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  flex-direction: column;\n}\n\n.Ghost {\n  transform: translate(0px, -25px);\n  z-index: -1;\n  animation: opacidad 4s infinite ease-in-out;\n}\n\n@keyframes opacidad {\n  0% {\n    opacity: 1;\n    scale: 1;\n  }\n\n  50% {\n    opacity: 0.5;\n    scale: 0.9;\n  }\n\n  100% {\n    opacity: 1;\n    scale: 1;\n  }\n}\n\n@keyframes estroboscopico {\n  0% {\n    opacity: 1;\n  }\n\n  50% {\n    opacity: 0;\n  }\n\n  51% {\n    opacity: 1;\n  }\n\n  100% {\n    opacity: 1;\n  }\n}\n\n@keyframes rebote {\n  0%,\n  100% {\n    transform: translateY(0);\n  }\n\n  50% {\n    transform: translateY(-10px);\n  }\n}\n\n@keyframes estroboscopico1 {\n  0%,\n  50%,\n  100% {\n    fill: rgb(255, 95, 74);\n  }\n\n  25%,\n  75% {\n    fill: rgb(16, 53, 115);\n  }\n}\n\n@keyframes estroboscopico2 {\n  0%,\n  50%,\n  100% {\n    fill: #17e300;\n  }\n\n  25%,\n  75% {\n    fill: #17e300b4;\n  }\n}\n\n.SevMini {\n  animation: rebote 4s infinite ease-in-out;\n}\n\n#strobe_led1 {\n  animation: estroboscopico 0.5s infinite;\n}\n\n#strobe_color1 {\n  animation: estroboscopico2 0.8s infinite;\n}\n\n#strobe_color3 {\n  animation: estroboscopico1 0.8s infinite;\n  animation-delay: 3s;\n}"
