    "css": "/* From Uiverse.io by jdm-encompass - Tags: button, social media, animated, follow */\n.button {\n  background-color: #1877F2;\n  border: none;\n  border-radius: 50%;\n  box-shadow: 0 0 20px 0 rgba(0, 0, 0, 0.5);\n  animation: sway 2s infinite alternate;\n  width: 70px;\n  height: 70px;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  perspective: 500px;\n  transition: transform 0.5s, box-shadow 0.5s;\n}\n\n.button:hover {\n  transform: rotate(-360deg);\n  box-shadow: 0 0 20px 0 rgba(0, 0, 255, 0.5);\n}\n\n@keyframes grow {\n  0% {\n    transform: scale(1);\n  }\n\n  100% {\n    transform: scale(10);\n  }\n}\n\n@keyframes glow {\n  0% {\n    text-shadow: gold 1px 1px 1px;\n  }\n\n  100% {\n    text-shadow: gold 0 0 10px gold;\n  }\n}\n\n.icon {\n  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.6));\n  transition: transform 0.5s;\n}\n\n.icon:hover {\n  transform: scale(1.5);\n  filter: drop-shadow(1px 2px 4px rgba(0,0,0,0.9))\n}\n\n.follow-text {\n  color: white;\n  position: relative;\n  top: 3em;\n  left: -4em;\n  transition: transform 0.5s;\n}\n\n.follow-text:hover {\n  transform: scale(1.2);\n  color: rgba(31,81,255,100);\n  filter: drop-shadow(2px 2px 4px rgba(31,81,255,2.0))\n}"
