    "css": "/* From Uiverse.io by FoxVidaan - Tags: card */\n.card {\n  max-width: 300px;\n  font-family: sans-serif;\n  color: white;\n  background: linear-gradient(-45deg, #7121A6, #520153, #044146, #04967b );\n  background-size: 400% 400%;\n  animation: gradient 12s ease infinite;\n  padding: 2rem;\n  display: flex;\n  flex-direction: column;\n  gap: 1.5rem;\n  border-radius: 10px;\n}\n\n.heading {\n  position: relative;\n  overflow: hidden;\n  font-size: 1.2rem;\n  font-weight: 600;\n  text-align: center;\n  padding-bottom: 10px;\n}\n\n.heading span {\n  display: block;\n  margin-top: -0.5rem;\n  font-size: 2.7rem;\n  font-weight: 800;\n  -webkit-text-stroke: #fff 0.1rem;\n  letter-spacing: 0.2rem;\n  color: transparent;\n  position: relative;\n  /* top: 10rem; */\n  /* animation: slide-in 0.4s 1s both; */\n  text-shadow: 0px 0px 16px #CECECE;\n}\n\n.content {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  gap: 0.8rem;\n}\n\n.content .item {\n  width: 110px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  gap: 0.5rem;\n  padding: 10px 16px;\n  background: rgba( 255, 255, 255, 0.05 );\n  box-shadow: 0 0 2px 2px rgba(255, 255, 255, 0.37);\n  backdrop-filter: blur( 3px );\n  -webkit-backdrop-filter: blur( 3px );\n  border-radius: 10px;\n}\n\n.content .item:first-child {\n  align-self: flex-start;\n}\n\n.content .item:last-child {\n  align-self: flex-end;\n}\n\n.content .item.item--create:hover svg {\n  animation: create-animation 1s infinite alternate;\n}\n\n.content .item.item--post:hover svg {\n  animation: post-animation 2s infinite;\n}\n\n.content .item.item--inspire:hover svg {\n  animation: inspire-animation 2s infinite;\n}\n\nbutton {\n  cursor: pointer;\n  margin-top: 0.5rem;\n  font-weight: 800;\n  font-size: 0.8rem;\n  text-transform: uppercase;\n  letter-spacing: 0.1rem;\n  color: #7121a6af;\n  animation: text-color 12s ease infinite;\n  background-color: #ffffffbb;\n  border: none;\n  border-radius: 20px;\n  padding: 16px 24px;\n  transition: 0.4s;\n  box-shadow: -4px -2px 10px 0px #ffffffbb, 4px 2px 16px 0px #02735e80;\n}\n\nbutton:hover {\n  color: #7121a6;\n  background-color: #ffffff;\n  box-shadow: -2px -1px 8px 0px #ffffff, 2px 1px 8px 0px #02735e;\n}\n\nbutton:active {\n  box-shadow: none;\n}\n\n@keyframes gradient {\n  0% {\n    background-position: 0% 50%;\n  }\n\n  50% {\n    background-position: 100% 50%;\n  }\n\n  100% {\n    background-position: 0% 50%;\n  }\n}\n\n@keyframes slide-in {\n  100% {\n    top: 0rem;\n  }\n}\n\n@keyframes create-animation {\n  0% {\n    transform: scaleX(0.8);\n  }\n\n  100% {\n    transform: scaleX(1.2);\n  }\n}\n\n@keyframes post-animation {\n  0%, 100% {\n    transform: rotate(-90deg) translateY(0%);\n  }\n\n  45% {\n    transform: rotate(-90deg) translateY(-50%);\n  }\n\n  50% {\n    transform: rotate(-90deg) translateY(-50%) scaleY(-1);\n  }\n\n  55% {\n    transform: rotate(-90deg) translateY(-50%) scaleY(-1);\n  }\n\n  90% {\n    transform: rotate(-90deg) translateY(0%) scaleY(-1);\n  }\n}\n\n@keyframes inspire-animation {\n  0%,60% {\n    filter: brightness(0.8) drop-shadow(0px 0px 2px rgb(0 0 0 / 0.4));\n  }\n\n  30%,100% {\n    filter: brightness(1) drop-shadow(0px 0px 2px rgba(255, 255, 255, 0.4));\n  }\n}\n\n@keyframes text-color {\n  0% {\n    color: #02735E;\n  }\n\n  50% {\n    color: #7121a6;\n  }\n\n  100% {\n    color: #02735E;\n  }\n}"
