    "css": "/* From Uiverse.io by yaroslavas2001 - Tags: card */\n.card {\n  padding: 20px 10px;\n  border-radius: 10%;\n  height: 280px;\n  width: 250px;\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  color: white;\n}\n\n.card::before,\n.card::after {\n  content: '';\n  position: absolute;\n  z-index: -1;\n  filter: blur(29px);\n  border-radius: 50%;\n}\n\n.card::before {\n  border: 30px dashed #2061c2;\n  width: 200px;\n  height: 250px;\n  bottom: 90px;\n  animation: 11s linear 0s normal none infinite running borderBefore;\n}\n\n.card::after {\n  border: 30px dashed #9238BD;\n  width: 250px;\n  height: 200px;\n  animation: 9s linear 0s normal none infinite running borderAfter;\n}\n\n.heading {\n  font-weight: bold;\n  text-align: center;\n  color: #F2F2F2;\n}\n\n.heading span {\n  letter-spacing: 4px;\n  line-height: 25px;\n}\n\n.content {\n  height: 100%;\n  width: 100%;\n  display: flex;\n  flex-direction: column;\n  padding: 10px;\n  position: relative;\n}\n\n.content::before {\n  content: '';\n  font-size: 15px;\n  position: absolute;\n  filter: blur(19px);\n  border-radius: 50%;\n  border: 15px dashed #6f21a3;\n  width: 100px;\n  height: 150px;\n  top: 0px;\n  left: 50px;\n  z-index: -1;\n  animation: 11s linear 0s normal none infinite running borderAfter;\n}\n\n@keyframes borderBefore {\n  0% {\n    transform: rotate(360deg);\n  }\n\n  100% {\n    transform: rotate(0deg);\n  }\n}\n\n@keyframes borderAfter {\n  0% {\n    transform: rotate(0deg);\n  }\n\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n.item {\n  height: 100%;\n  width: 100%;\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  text-align: center;\n  cursor: pointer;\n}\n\n.item svg {\n  margin-right: 10px;\n}\n\n.item {\n  position: relative;\n  transition: opacity .5s ease-out;\n}\n\n.item:hover {\n  font-weight: bold;\n}\n\n.item::before,\n.item::after {\n  opacity: 0;\n  width: 5px;\n  height: 5px;\n  border-radius: 20px;\n  position: absolute;\n  background: rgba(255, 255, 255, 0.3);\n  box-shadow: 10px 10px 17px 20px  rgba(255, 255, 255, 0.3);\n  transition: opacity .5s ease-out;\n  animation: 8s linear 0s normal none infinite running item;\n}\n\n@keyframes item {\n  0% {\n    transform: translateX(0px) translateY(0px);\n  }\n\n  25% {\n    transform: translateX(5px) translateY(-10px);\n  }\n\n  50% {\n    transform: translateX(10px) translateY(10px);\n  }\n\n  75% {\n    transform: translateX(5px) translateY(-10px);\n  }\n\n  100% {\n    transform: translateX(0px) translateY(0px);\n  }\n}\n\n.item::before {\n  left: 0px;\n  top: 10px;\n}\n\n.item::after {\n  right: 30px;\n  top: 10px;\n}\n\n.item--create::before {\n  content: '💻';\n}\n\n.item--create:hover::before {\n  opacity: 1;\n}\n\n.item--create:after {\n  content: '📈';\n}\n\n.item--create:hover:after {\n  opacity: 1;\n}\n\n.item--post::before {\n  content: '🌌';\n}\n\n.item--post:hover::before {\n  opacity: 1;\n}\n\n.item--post:after {\n  content: '🎆';\n}\n\n.item--post:hover:after {\n  opacity: 1;\n}\n\n.item--inspire::before {\n  content: '✨';\n}\n\n.item--inspire:hover::before {\n  opacity: 1;\n}\n\n.item--inspire:after {\n  content: '🌊';\n}\n\n.item--inspire:hover:after {\n  opacity: 1;\n}\n\nbutton {\n  background: transparent;\n  border: 0px;\n  border-radius: 20px;\n  padding: 10px 30px;\n  color: #fff;\n  font-weight: bold;\n  cursor: pointer;\n  position: relative;\n  animation: 0.9s linear 0s normal none infinite running button;\n  transition: all .5s ease-out;\n}\n\nbutton:hover {\n  letter-spacing: 1px;\n}\n\n@keyframes button {\n  0% {\n    border: 2px dotted rgba(73, 53, 247, 0.9);\n  }\n\n  100% {\n    border: 2px dashed rgba(120, 12, 243,0.9);\n  }\n}"
