    "css": "/* From Uiverse.io by Jamshibkl - Tags: card */\n.card {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  flex-direction: column;\n  width: 280px;\n  height: 350px;\n  padding: 30px;\n  border-radius: 18px;\n  position: relative;\n  box-sizing: border-box;\n  background: linear-gradient(90deg, #0a76b5 0%, #3bf8a0 100%);\n  animation: gradient 8s ease-in-out infinite;\n  background-size: 500% 500%;\n  transition: all 0.5s;\n  box-shadow: 0px 15px 20px rgba(32, 64, 194, 0.4);\n}\n\n.heading {\n  font-size: 25px;\n  font-weight: bold;\n  color: rgb(15, 17, 36);\n  margin-top: 20px;\n  text-shadow: 0 0.25em 0.5em rgba(0, 0, 0, 0.3);\n  ;\n}\n\n.heading span {\n  color: #ffffffeb;\n  text-shadow: 0px 0px 16px #CECECE;\n}\n\n.content {\n  display: flex;\n  justify-content: space-between;\n  list-style: none;\n  background-color: #17181c;\n  border-radius: 1em;\n  box-shadow: 0 0.25em 0.5em rgba(0, 0, 0, 0.3);\n  transform-origin: 50% 133%;\n  text-shadow: 0px 0px 16px #CECECE;\n}\n\n.content:hover {\n  box-shadow: 0px 15px 20px rgba(32, 64, 194, 0.4);\n}\n\n.item {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  text-align: center;\n  width: 5rem;\n  height: 4rem;\n  text-decoration: none;\n  transition: transform 0.2s ease-in-out;\n  color: #ffffff;\n  text-shadow: 0px 0px 16px #CECECE;\n}\n\n.item:hover {\n  color: dodgerblue;\n  transform: translateY(-10px);\n}\n\n.item:focus {\n  outline: transparent;\n}\n\n.item item--create svg {\n  display: block;\n  margin: 0 auto;\n  overflow: visible;\n  width: 1.5em;\n  height: 1.5em;\n  transition: transform 0.3s cubic-bezier(0.7,0,0.3,1);\n}\n\n.item span {\n  display: block;\n  font-size: 10px;\n  line-height: 1.25;\n  text-align: center;\n  transition: opacity 0.3s;\n}\n\n.item--create svg {\n  animation: spin 2s linear infinite;\n}\n\n.item--post svg {\n  animation: upDown 2s ease-in-out infinite alternate;\n}\n\n.item--inspire svg {\n  animation: flash 1.2s linear infinite;\n}\n\n@keyframes spin {\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n@keyframes upDown {\n  0% {\n    transform: translateY(1.8px);\n  }\n\n  100% {\n    transform: translateY(-1.8px);\n  }\n}\n\n@keyframes flash {\n  0% {\n    opacity: 1;\n  }\n\n  50% {\n    opacity: 0;\n  }\n\n  100% {\n    opacity: 1;\n  }\n}\n\n.content span:hover {\n  color: dodgerblue;\n  text-shadow: 0px 0px 16px #CECECE;\n}\n\n.item:focus span {\n  opacity: 0;\n}\n\nbutton {\n  padding: 15px;\n  font-size: 12px;\n  text-transform: uppercase;\n  text-shadow: 0px 0px 16px #CECECE;\n  letter-spacing: 2.5px;\n  font-weight: 500;\n  color: #fff;\n  background-color: rgb(12, 17, 80);\n  border: none;\n  border-radius: 25px;\n  box-shadow: 0 0.25em 0.5em rgba(0, 0, 0, 0.3);\n  transition: all 0.3s ease 0s;\n  cursor: pointer;\n  outline: none;\n}\n\nbutton:hover {\n  background-color: #251ab6;\n  box-shadow: 0px 15px 20px rgba(32, 64, 194, 0.4);\n  color: #fff;\n  transform: translateY(-7px);\n}\n\nbutton:active {\n  transform: translateY(-1px);\n}"
