    "css": "/* From Uiverse.io by Tsiangana  - Tags: glassmorphism, card, social media, hover effect */\n.card {\n  width: 220px;\n  height: 350px;\n  border-radius: 15px;\n  backdrop-filter: blur(15px);\n  background-color: #8ec5fc0a;\n  background-image: linear-gradient(62deg, #8ec5fc21 0%, #e0c3fc3b 100%);\n  box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.1);\n  border: 1px solid rgba(255, 255, 255, 0.5);\n  transition: all 0.2s ease-in-out;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n}\n\n.card::after {\n  content: \"\";\n  position: absolute;\n  top: 10px;\n  left: 10px;\n  width: 40px;\n  height: 40px;\n  background-color: #fff;\n  border-radius: 50%;\n}\n\n.card::before {\n  content: \"Follom me\";\n  bottom: 30px;\n  position: absolute;\n  width: 130px;\n  height: 22px;\n  border-radius: 20px;\n  background: #fff;\n  box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.1);\n  font-size: 12px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-weight: 600;\n  font-family: -apple-system, BlinkMacSystemFont, \"Segoe UI\", Roboto, Oxygen,\n    Ubuntu, Cantarell, \"Open Sans\", \"Helvetica Neue\", sans-serif;\n}\n\n.card:hover > .image {\n  height: 65%;\n  filter: blur(7px);\n  animation: anim 3s infinite;\n}\n\n@keyframes anim {\n  0% {\n    transform: translateY(0);\n  }\n\n  50% {\n    transform: translateY(-20px);\n  }\n\n  100% {\n    transform: translateY(0);\n  }\n}\n\n.card:hover {\n  transform: scale(1.04) rotate(-1deg);\n}\n\n.card .image {\n  width: 170px;\n  margin-top: -20px;\n}\n\n.card .heading {\n  position: absolute;\n  color: #fff;\n  font-size: 17px;\n  font-weight: 600;\n}\n.card .icons a {\n  color: #fff;\n  position: absolute;\n  cursor: pointer;\n  z-index: 5;\n}\n\n.card .icons a:nth-child(1) {\n  top: 200px;\n  left: 203px;\n  width: 35px;\n  height: 35px;\n  border-radius: 50%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  color: #cc39a4;\n  background-color: #fff;\n  box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.1);\n  transition: all 0.2s ease-in-out;\n}\n\n.card .icons a:nth-child(1):hover {\n  background-color: #cc39a4;\n  border: 1px solid rgba(255, 255, 255, 0.5);\n  color: #fff;\n  transition: all 0.2s ease-in-out;\n}\n\n.card .icons a:nth-child(2) {\n  top: 240px;\n  left: 203px;\n  width: 35px;\n  height: 35px;\n  border-radius: 50%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  color: #000;\n  background-color: #fff;\n  box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.1);\n  transition: all 0.2s ease-in-out;\n}\n\n.card .icons a:nth-child(2):hover {\n  background-color: #000;\n  border: 1px solid rgba(255, 255, 255, 0.5);\n  color: #fff;\n  transition: all 0.2s ease-in-out;\n}\n\n.card .icons a:nth-child(3) {\n  top: 280px;\n  left: 203px;\n  width: 35px;\n  height: 35px;\n  border-radius: 50%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  color: #8c9eff;\n  background-color: #fff;\n  box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.1);\n  transition: all 0.2s ease-in-out;\n}\n\n.card .icons a:nth-child(3):hover {\n  background-color: #8c9eff;\n  border: 1px solid rgba(255, 255, 255, 0.5);\n  color: #fff;\n  transition: all 0.2s ease-in-out;\n}"
