    "css": "/* From Uiverse.io by MuhammadHasann  - Tags: simple, animation, gradient, card, card animation */\n.card {\n  --white: hsl(0, 0%, 100%);\n  --black: hsl(240, 15%, 9%);\n  --paragraph: hsl(0, 0%, 83%);\n  --line: hsl(240, 9%, 17%);\n  --primary: hsl(266, 92%, 58%);\n\n  position: relative;\n\n  display: flex;\n  flex-direction: column;\n  gap: 1rem;\n\n  padding: 1rem;\n  width: 19rem;\n  background-color: hsla(240, 15%, 9%, 1);\n  background-image: radial-gradient(\n      at 88% 40%,\n      hsla(240, 15%, 9%, 1) 0px,\n      transparent 85%\n    ),\n    radial-gradient(at 49% 30%, hsla(240, 15%, 9%, 1) 0px, transparent 85%),\n    radial-gradient(at 14% 26%, hsla(240, 15%, 9%, 1) 0px, transparent 85%),\n    radial-gradient(at 0% 64%, hsla(263, 93%, 56%, 1) 0px, transparent 85%),\n    radial-gradient(at 41% 94%, hsla(284, 100%, 84%, 1) 0px, transparent 85%),\n    radial-gradient(at 100% 99%, hsla(306, 100%, 57%, 1) 0px, transparent 85%);\n\n  border-radius: 1rem;\n  box-shadow: 0px -16px 24px 0px rgba(255, 255, 255, 0.25) inset;\n}\n\n.card .card__border {\n  overflow: hidden;\n  pointer-events: none;\n\n  position: absolute;\n  z-index: -10;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%);\n\n  width: calc(100% + 2px);\n  height: calc(100% + 2px);\n  background-image: linear-gradient(\n    0deg,\n    hsl(0, 0%, 100%) -50%,\n    hsl(0, 0%, 40%) 100%\n  );\n\n  border-radius: 1rem;\n}\n\n.card .card__border::before {\n  content: \"\";\n  pointer-events: none;\n\n  position: fixed;\n  z-index: 200;\n  top: 50%;\n  left: 50%;\n  transform: translate(-50%, -50%), rotate(0deg);\n  transform-origin: left;\n\n  width: 200%;\n  height: 10rem;\n  background-image: linear-gradient(\n    0deg,\n    hsla(0, 0%, 100%, 0) 0%,\n    hsl(277, 95%, 60%) 40%,\n    hsl(277, 95%, 60%) 60%,\n    hsla(0, 0%, 40%, 0) 100%\n  );\n\n  animation: rotate 8s linear infinite;\n}\n\n@keyframes rotate {\n  to {\n    transform: rotate(360deg);\n  }\n}\n\n.card .card_title__container .card_title {\n  font-size: 1rem;\n  color: var(--white);\n}\n\n.card .card_title__container .card_paragraph {\n  margin-top: 0.25rem;\n  width: 65%;\n\n  font-size: 0.5rem;\n  color: var(--paragraph);\n}\n\n.card .line {\n  width: 100%;\n  height: 0.1rem;\n  background-color: var(--line);\n\n  border: none;\n}\n\n.card .card__list {\n  display: flex;\n  flex-direction: column;\n  gap: 0.5rem;\n}\n\n.card .card__list .card__list_item {\n  display: flex;\n  align-items: center;\n  gap: 0.5rem;\n}\n\n.card .card__list .card__list_item .check {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n\n  width: 1rem;\n  height: 1rem;\n  background-color: var(--primary);\n\n  border-radius: 50%;\n}\n\n.card .card__list .card__list_item .check .check_svg {\n  width: 0.75rem;\n  height: 0.75rem;\n\n  fill: var(--black);\n}\n\n.card .card__list .card__list_item .list_text {\n  font-size: 0.75rem;\n  color: var(--white);\n}\n\n.card .button {\n  cursor: pointer;\n\n  padding: 0.5rem;\n  width: 100%;\n  background-image: linear-gradient(\n    0deg,\n    rgba(94, 58, 238, 1) 0%,\n    rgba(197, 107, 240, 1) 100%\n  );\n\n  font-size: 0.75rem;\n  color: var(--white);\n\n  border: 0;\n  border-radius: 9999px;\n  box-shadow: inset 0 -2px 25px -4px var(--white);\n}"
