    "css": "/* From Uiverse.io by Yaya12085  - Tags: animation, social, card, hover, social media, cool card */\n.card {\n  --color1: #af40ff;\n  --color2: #5b42f3;\n  --color3: #00ddeb;\n  max-width: 350px;\n  box-sizing: border-box;\n  height: 270px;\n  width: 450px;\n  border-radius: 12px;\n  padding: 12px;\n  position: relative;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  flex-direction: column;\n  gap: 30px;\n  background: -webkit-radial-gradient(\n      center,\n      circle,\n      rgba(255, 255, 255, 0.35),\n      rgba(255, 255, 255, 0) 20%,\n      rgba(255, 255, 255, 0) 21%\n    ),\n    -webkit-radial-gradient(center, circle, rgba(0, 0, 0, 0.2), rgba(0, 0, 0, 0)\n          20%, rgba(0, 0, 0, 0) 21%),\n    -webkit-radial-gradient(center, circle farthest-corner, #f0f0f0, #c0c0c0);\n  background: -moz-radial-gradient(\n      center,\n      circle,\n      rgba(255, 255, 255, 0.35),\n      rgba(255, 255, 255, 0) 20%,\n      rgba(255, 255, 255, 0) 21%\n    ),\n    -webkit-radial-gradient(center, circle, rgba(0, 0, 0, 0.2), rgba(0, 0, 0, 0)\n          20%, rgba(0, 0, 0, 0) 21%),\n    -webkit-radial-gradient(center, circle farthest-corner, #f0f0f0, #c0c0c0);\n  background: -ms-radial-gradient(\n      center,\n      circle,\n      rgba(255, 255, 255, 0.35),\n      rgba(255, 255, 255, 0) 20%,\n      rgba(255, 255, 255, 0) 21%\n    ),\n    -webkit-radial-gradient(center, circle, rgba(0, 0, 0, 0.2), rgba(0, 0, 0, 0)\n          20%, rgba(0, 0, 0, 0) 21%),\n    -webkit-radial-gradient(center, circle farthest-corner, #f0f0f0, #c0c0c0);\n  background: -o-radial-gradient(\n      center,\n      circle,\n      rgba(255, 255, 255, 0.35),\n      rgba(255, 255, 255, 0) 20%,\n      rgba(255, 255, 255, 0) 21%\n    ),\n    -webkit-radial-gradient(center, circle, rgba(0, 0, 0, 0.2), rgba(0, 0, 0, 0)\n          20%, rgba(0, 0, 0, 0) 21%),\n    -webkit-radial-gradient(center, circle farthest-corner, #f0f0f0, #c0c0c0);\n  background: radial-gradient(\n      center,\n      circle,\n      rgba(255, 255, 255, 0.35),\n      rgba(255, 255, 255, 0) 20%,\n      rgba(255, 255, 255, 0) 21%\n    ),\n    -webkit-radial-gradient(center, circle, rgba(0, 0, 0, 0.2), rgba(0, 0, 0, 0)\n          20%, rgba(0, 0, 0, 0) 21%),\n    -webkit-radial-gradient(center, circle farthest-corner, #f0f0f0, #c0c0c0);\n  background-size: 10px 10px, 10px 10px, 100% 100%;\n  background-position: 1px 1px, 0px 0px, center center;\n}\n.card::before,\n.card::after {\n  position: absolute;\n  content: \"\";\n  bottom: 10px;\n  width: 40%;\n  height: 10px;\n  box-shadow: 0 5px 14px rgba(0, 0, 0, 0.7);\n  z-index: -1;\n  transition: all 0.3s ease;\n}\n\n.card::before {\n  left: 15px;\n  transform: skew(-5deg) rotate(-5deg);\n}\n\n.card::after {\n  right: 15px;\n  transform: skew(5deg) rotate(5deg);\n}\n\n.card:hover::before,\n.card:hover::after {\n  box-shadow: 0 2px 14px rgba(0, 0, 0, 0.4);\n}\n\n.image {\n  position: absolute;\n  height: 100px;\n  object-fit: cover;\n  top: -20%;\n  left: 50%;\n\n  transform: translateX(-200%) rotate(45deg);\n  transition-timing-function: cubic-bezier(0.64, 0.57, 0.67, 1.53);\n  transition-duration: 1s;\n}\n.heading {\n  font-size: 30px;\n  text-align: center;\n  font-weight: 900;\n\n  background: linear-gradient(\n    144deg,\n    var(--color1),\n    var(--color2),\n    var(--color3)\n  );\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n}\n\n.icons {\n  display: flex;\n  gap: 30px;\n}\n.icons a {\n  padding: 10px;\n  border-radius: 10px;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  border: double 2px transparent;\n  background-image: linear-gradient(white, white),\n    linear-gradient(144deg, var(--color1), var(--color2), var(--color3));\n  background-clip: padding-box, border-box;\n  background-origin: border-box;\n  transition-timing-function: cubic-bezier(0.64, 0.57, 0.67, 1.53);\n  transition-duration: 0.3s;\n}\n.icons a:hover {\n  border-radius: 40px;\n}\n.instagram {\n  color: var(--color1);\n}\n.x {\n  color: var(--color2);\n}\n.discord {\n  color: var(--color3);\n}\n\n.card:hover::before,\n.card:hover::after {\n  box-shadow: 0 2px 14px rgba(0, 0, 0, 0.4);\n}\n.card:hover .image {\n  animation: animate 2s linear infinite alternate;\n}\n\n@keyframes animate {\n  0% {\n    transform: translateX(-200%) rotate(45deg);\n  }\n  100% {\n    transform: translateX(100%) rotate(-45deg);\n  }\n}"
